import type { TreeNodeConfig } from '../../tree/interface';

export function generateTreeData({
  disable1 = false,
}: {
  disable1?: boolean;
} = {}) {
  const n = 3;
  const treeData: TreeNodeConfig[] = [];
  for (let i = 0; i < n; i++) {
    const vi = `${i + 1}`;
    const node: TreeNodeConfig = {
      label: `一级 ${vi}`,
      value: vi,
      disabled: Boolean(disable1 && i === 0),
      children: [],
    };
    treeData.push(node);
    for (let j = 0; j < n; j++) {
      const vj = `${i + 1}-${j + 1}`;
      const _node: TreeNodeConfig = {
        label: `二级 ${vj}`,
        value: vj,
        children: [],
      };
      node.children.push(_node);
      for (let k = 0; k < n; k++) {
        const vk = `${i + 1}-${j + 1}-${k + 1}`;
        const __node: TreeNodeConfig = {
          label: `三级 ${vk}`,
          value: vk,
          children: [],
        };
        _node.children.push(__node);
        // eslint-disable-next-line max-depth
        if (k !== 0) {
          continue;
        }
        // eslint-disable-next-line max-depth
        for (let o = 0; o < n; o++) {
          const vo = `${i + 1}-${j + 1}-${k + 1}-${o + 1}`;
          const ___node: TreeNodeConfig = {
            label: `四级 ${vo}`,
            value: vo,
            children: [],
          };
          __node.children.push(___node);
        }
      }
    }
  }
  return treeData;
}
